}
.my-opinions-inview-container{
    display: flex;
    width: 100%;
    height: 10px;
}
/* ── Avatar Badge Rings ── */
.so-avatar-container,
.so-avatar-outer,
.ov-avatar-container,
.rc-avatar-container,
.opinions-profile-container {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
}
.avatar-ring-legend {
    border: 2px solid #FFD700;
    box-shadow:
        0 0 6px 1px rgba(255, 215, 0, 0.5),
        0 0 12px 2px rgba(255, 215, 0, 0.35),
        0 0 20px 4px rgba(255, 215, 0, 0.2);
    animation: glow-legend 2s ease-in-out infinite alternate;
}
.avatar-ring-og {
    border: 2px solid #9B59FF;
    box-shadow:
        0 0 6px 1px rgba(155, 89, 255, 0.5),
        0 0 12px 2px rgba(155, 89, 255, 0.35),
        0 0 20px 4px rgba(155, 89, 255, 0.2);
    animation: glow-og 2s ease-in-out infinite alternate;
}

@keyframes glow-legend {
    from {
        box-shadow:
            0 0 6px 1px rgba(255, 215, 0, 0.5),
            0 0 12px 2px rgba(255, 215, 0, 0.35),
            0 0 20px 4px rgba(255, 215, 0, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(255, 215, 0, 0.6),
            0 0 16px 4px rgba(255, 215, 0, 0.4),
            0 0 24px 6px rgba(255, 215, 0, 0.25);
    }
}

@keyframes glow-og {
    from {
        box-shadow:
            0 0 6px 1px rgba(155, 89, 255, 0.5),
            0 0 12px 2px rgba(155, 89, 255, 0.35),
            0 0 20px 4px rgba(155, 89, 255, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(155, 89, 255, 0.6),
            0 0 16px 4px rgba(155, 89, 255, 0.4),
            0 0 24px 6px rgba(155, 89, 255, 0.25);
    }
}
.so-avatar-outer.avatar-ring-legend,
.so-avatar-outer.avatar-ring-og {
    display: flex;
    align-items: center;
    justify-content: center;
    width: auto;
    height: auto;
}
.so-avatar-outer.avatar-ring-legend .so-avatar,
.so-avatar-outer.avatar-ring-og .so-avatar {
    width: 36px;
    height: 36px;
}

/* ── Sidebar Opinion Card (so-) ── */
.so-card-wrapper {
    display: block;
    width: 100%;
    box-sizing: border-box;
    border-bottom: none;
    padding: 0;
    margin-bottom: 0.45rem;
}
.so-avatar-outer {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 34px;
    height: 34px;
    border-radius: 50%;
    background-color: transparent;
    cursor: pointer;
}
.so-avatar-outer .so-avatar {
    width: 34px;
    height: 34px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid var(--border-card);
}
.so-card {
    display: flex;
    flex-direction: column;
    width: 100%;
    box-sizing: border-box;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    padding: 0.85rem 0.9rem;
    color: var(--text-primary);
    box-shadow: var(--shadow-card-sm);
    transition: box-shadow 0.2s ease, border-color 0.2s ease;
}
.visited-profile-opinions-container .so-card {
    border: none;
    box-shadow: var(--shadow-card-sm);
}
.so-card:hover {
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
}
.so-card-content{
    display: flex;
    flex-direction: column;
    gap: 0.65rem;
    min-width: 0;
}
.so-card--profile{
    background-color: var(--bg-card);
}
.so-card--profile::before{
    content: none;
}
.so-card--profile .so-username,
.so-card--profile .so-body,
.so-card--profile .ov-date{
    color: inherit;
}
.so-card--profile .so-handle{
    color: var(--text-muted);
}
.so-card--profile .so-meta-bar{
    border-top-color: transparent;
}
.so-card--profile .so-reply-pill{
    color: var(--text-muted);
    border: none;
    background: transparent;
}
.so-card--profile .so-reply-pill:hover{
    background: transparent;
}

.so-user-row {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 0.6rem;
}
.visited-profile-opinions-container .so-user-row {
    padding-bottom: 0;
    border-bottom: none;
}
.so-user-meta{
    display: flex;
    align-items: flex-start;
    gap: 0.7rem;
    min-width: 0;
}
.so-card--profile .so-avatar-container{
    background-color: var(--bg-card);
    padding: 3px;
    border-radius: 50%;
}
.so-name-block{
    display: flex;
    flex-direction: column;
    gap: 0.12rem;
    min-width: 0;
}
.so-name-line{
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    min-width: 0;
}
.so-handle{
    font-family: "Inter", "Nunito", sans-serif;
    font-size: 0.72rem;
    color: var(--text-muted);
    opacity: 1;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 150px;
}
.so-date-row{
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
}
.so-avatar {
    width: 34px;
    height: 34px;
    border-radius: 50%;
    object-fit: cover;
    cursor: pointer;
}
.so-username {
    font-family: "Bradley Hand", "Segoe Print", "Comic Sans MS", cursive;
    font-size: 1.02rem;
    font-weight: 700;
    color: var(--text-heading);
    cursor: pointer;
}
.so-username:hover {
    color: var(--accent-amber);
    text-decoration: underline;
}

.so-body {
    font-family: "Inter", "Nunito", sans-serif;
    font-size: clamp(1.02rem, 0.96rem + 0.25vw, 1.2rem);
    line-height: 1.35;
    color: var(--text-primary);
    cursor: pointer;
    margin-left: 2.75rem;
    overflow-wrap: anywhere;
    word-break: break-word;
    white-space: pre-wrap;
    display: block;
}

.so-meta-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.6rem;
    margin-left: 2.75rem;
    padding-top: 0.1rem;
    border-top: none;
}
.visited-profile-opinions-container .so-meta-bar {
    padding-top: 0.1rem;
    border-top: none;
}
.so-reply-pill {
    display: inline-flex;
    align-items: center;
    gap: 0.38rem;
    background-color: transparent;
    border-radius: 0;
    padding: 0;
    font-family: "Inter", "Nunito", sans-serif;
    font-size: 0.86rem;
    font-weight: 500;
    color: var(--text-muted);
    cursor: pointer;
    transition: color 0.15s ease;
}
.so-reply-pill:hover {
    background-color: transparent;
    color: var(--text-secondary);
}

.opinions-page-parent-container .so-card-wrapper {
    width: min(720px, 92%);
    margin: 0 auto 0.45rem auto;
}

/* ── Opinion Viewer (ov-) ── */
.ov-card {
    display: flex;
    flex-direction: column;
    width: 100%;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 14px;
    padding: 1.15rem;
    gap: 0.75rem;
    box-sizing: border-box;
    transition: box-shadow 0.25s ease;
    margin-bottom: 1rem;
}
.ov-card:hover {
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
}

.ov-user-row {
    display: flex;
    align-items: center;
    gap: 0.45rem;
}
.ov-avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
}
.ov-username {
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--text-heading);
    cursor: pointer;
    transition: color 0.15s ease;
}
.ov-username:hover {
    color: var(--accent-amber);
    text-decoration: underline;
}
.ov-dot {
    color: var(--text-separator);
    font-size: 0.8rem;
    line-height: 1;
}
.ov-date {
    font-family: var(--font-ui);
    font-size: 0.75rem;
    color: var(--text-faint);
}

.ov-body {
    font-family: var(--font-serif);
    font-size: 0.92rem;
    line-height: 1.7;
    color: var(--text-body);
    cursor: pointer;
}

.ov-meta-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 0.6rem;
    border-top: 1px solid var(--border-card);
}
.ov-reply-pill {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    background-color: var(--bg-pill);
    border-radius: 10px;
    padding: 0.2rem 0.6rem;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    cursor: pointer;
}
.ov-full-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

.ov-reply-row {
    display: flex;
    align-items: flex-end;
    gap: 0.5rem;
    padding-top: 0.25rem;
}
.ov-reply-avatar {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    object-fit: cover;
}
.ov-reply-input {
    flex: 1;
    min-height: 1.4rem;
    outline: none;
    border: none;
    border-bottom: 1px solid var(--border-card);
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-style: italic;
    color: var(--text-primary);
    padding-bottom: 0.25rem;
    transition: border-color 0.2s ease;
}
.ov-reply-input:empty::before {
    content: attr(data-placeholder);
    color: var(--text-faint);
    cursor: text;
}
.ov-reply-input:focus {
    border-bottom: 2px solid var(--accent-amber);
}

.ov-btn-row {
    display: flex;
    gap: 0.6rem;
    justify-content: flex-end;
    overflow: hidden;
}
.ov-btn-cancel {
    cursor: pointer;
    background-color: transparent;
    border: 1px solid var(--border-card);
    color: var(--text-primary);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 500;
    transition: background-color 0.15s ease;
}
.ov-btn-cancel:hover {
    background-color: var(--bg-hover);
}
.ov-btn-submit {
    cursor: pointer;
    border: none;
    padding: 0.35rem 1rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    transition: opacity 0.15s ease;
}
.ov-btn-submit:hover {
    opacity: 0.88;
}
.ov-btn-submit.ov-btn-disabled {
    cursor: default;
    user-select: none;
    opacity: 0.45;
}

/* ── Reply Card (rc-) ── */
.rc-thread {
    padding-left: calc(var(--depth, 0) * 1.25rem);
    width: 100%;
    box-sizing: border-box;
}

.rc-card {
    position: relative;
    display: flex;
    align-items: stretch;
    padding: 0.75rem 0;
    border-bottom: 1px solid var(--border-card);
}
.rc-card:last-child {
    border-bottom: none;
}

.rc-thread-line {
    position: absolute;
    left: -0.65rem;
    top: 0;
    bottom: 0;
    width: 2px;
    background-color: var(--border-card);
    border-radius: 1px;
    transition: background-color 0.2s ease;
}
.rc-card:hover > .rc-thread-line {
    background-color: var(--accent-amber);
}

.rc-content {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    flex: 1;
    min-width: 0;
}

.rc-user-row {
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.rc-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.rc-username {
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-heading);
}
.rc-dot {
    color: var(--text-separator);
    font-size: 0.75rem;
    line-height: 1;
}
.rc-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

.rc-body {
    font-family: var(--font-serif);
    font-size: 0.85rem;
    line-height: 1.65;
    color: var(--text-body);
}

.rc-action-row {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding-top: 0.15rem;
}
.rc-toggle-btn {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.2rem 0.4rem;
    border-radius: 6px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-muted);
    transition: color 0.15s ease, background-color 0.15s ease;
}
.rc-toggle-btn:hover {
    color: var(--accent-amber);
    background-color: var(--bg-pill);
}

.rc-reply-input-wrapper {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    overflow: hidden;
    padding-top: 0.25rem;
}

.rc-load-more {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    background: none;
    border: 1px solid var(--border-card);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    margin-top: 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--accent-amber);
    transition: background-color 0.15s ease;
}
.rc-load-more:hover {
    background-color: var(--bg-pill);
}
@media(max-width: 480px){
    .visited-profile-opinion-content{
        font-weight: 400;
