/* ── Opinion Editor (oe-) ── */
.oe-backdrop {
    display: flex;
    justify-content: center;
    align-items: center;
    position: fixed;
    inset: 0;
    background-color: rgba(0, 0, 0, 0.25);
    backdrop-filter: blur(12px);
    z-index: 130;
}

.oe-card {
    position: relative;
    display: flex;
    flex-direction: column;
    width: min(480px, 90%);
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    overflow: hidden;
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
    transition: box-shadow 0.25s ease;
}

.oe-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.85rem 1.15rem;
    border-bottom: 1px solid var(--border-card);
}
.oe-title {
    margin: 0;
    padding: 0;
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 650;
    color: var(--text-heading);
    letter-spacing: -0.01rem;
}
.oe-close-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    padding: 0;
    border: none;
    background: none;
    border-radius: 50%;
    color: var(--text-faint);
    cursor: pointer;
    transition: background-color 0.15s ease, color 0.15s ease;
}
.oe-close-btn:hover {
    background-color: var(--bg-pill);
    color: var(--text-heading);
}

.oe-body {
    padding: 0.75rem 1.15rem;
}
.oe-textarea {
    width: 100%;
    min-height: 120px;
    border: none;
    background-color: transparent;
    color: var(--text-body);
    font-family: var(--font-serif);
    font-size: 0.92rem;
    line-height: 1.7;
    letter-spacing: 0.005rem;
    resize: none;
    padding: 0;
    box-sizing: border-box;
}
.oe-textarea::placeholder {
    color: var(--text-faint);
}
.oe-textarea:focus {
    outline: none;
}

.oe-footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.6rem 1.15rem 0.85rem 1.15rem;
    border-top: 1px solid var(--border-card);
}
.oe-char-count {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 500;
    color: var(--text-faint);
    letter-spacing: 0.01rem;
    transition: color 0.15s ease;
}
.oe-char-warn {
    color: var(--accent-amber, #f59e0b);
}
.oe-char-limit {
    color: rgb(255, 116, 116);
}

.oe-save-btn {
    border: none;
    padding: 0.35rem 1.15rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.15s ease, transform 0.1s ease;
}
.oe-save-btn:hover {
    opacity: 0.88;
}
.oe-save-btn:active {
    transform: scale(0.97);
}
.oe-save-disabled {
    cursor: default;
    user-select: none;
    opacity: 0.4;
}
.oe-save-disabled:hover {
    opacity: 0.4;
}

.oe-loader {
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 3px;
    overflow: hidden;
    border-radius: 0 0 12px 12px;
}

.sidebar-opinions-cards-container{
