    align-items: center;
    position: relative;
    font-weight: 400;
    color: rgb(80, 80, 80);
    line-height: 1.2rem;
    font-size: 0.8rem;
    border-radius: 15px;
    padding: 0.8rem;
    background-color: rgba(212, 168, 83, 0.1);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05),
                0 1px 4px rgba(0, 0, 0, 0.05);
}
/* The larger circle */
.opinions-page-content::before {
    content: "";
    position: absolute;
    bottom: -15px;
    left: 30px;
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background-color: rgba(212, 168, 83, 0.25);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}
/* The smaller circle */
.opinions-page-content::after {
    content: "";
    position: absolute;
    bottom: -20px;
    left: 20px;
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background-color: rgba(212, 168, 83, 0.2);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}
.opinion-reply-button{
    position: absolute;
    bottom: -25px;
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.2rem 0.5rem;
    border-radius: 10px;
    background-color: rgba(212, 168, 83, 0.25);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05),
                0 1px 4px rgba(0, 0, 0, 0.05);
    gap: 0.2rem;
    color: rgb(80, 80, 80);
}
.mobile-write-opinions{
    display: flex;
    position: fixed;
    width: 100%;
    height: 120px;
    gap: 0.5rem;
    border-bottom: 0.7px solid #0000001b;
    background-color: #ffffff;
    z-index: 131;

}
.write-profile-container{
    display: flex;
    justify-content: flex-start;
    align-items: flex-start;
    width: fit-content;
    height: 100%;
    padding: 0rem 0 0 0.2rem;
}
.write-profile{
    width: 45px;
    height: 45px;
    border-radius: 50%;
    object-fit: cover;
}
.opinion-input-container{
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-end;
    width: 100%;
    height: 100%;
}
.mobile-input-opinion{
    width: 95%;
    height: 80%;
    padding: 0.4rem;
    border: none;
    background-color: rgb(255, 255, 255);
    color: #000000;
    font-family: "Nunito", sans-serif;
    font-size: 1.2rem;
}
.mobile-input-opinion:focus{
    outline: none;
}

.my-opinions-content{
    position: relative;
    margin: 0;
    font-weight: 400;
    color: rgb(80, 80, 80);
    line-height: 1.2rem;
    font-size: 0.8rem;
    border-radius: 15px;
    padding: 0.8rem 1rem;
    background-color: rgba(212, 168, 83, 0.1);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}

.see-fullpage-bttn{
    cursor: pointer;
    font-weight: 650;
    font-size: 0.78rem;
    color: var(--accent-amber);
    font-family: var(--font-ui);
