    font-size: 0.92rem;
    line-height: 1.7;
    color: var(--text-body);
    cursor: pointer;
}

.ov-meta-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 0.6rem;
    border-top: 1px solid var(--border-card);
}
.ov-reply-pill {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    background-color: var(--bg-pill);
    border-radius: 10px;
    padding: 0.2rem 0.6rem;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    cursor: pointer;
}
.ov-full-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

.ov-reply-row {
    display: flex;
    align-items: flex-end;
    gap: 0.5rem;
    padding-top: 0.25rem;
}
.ov-reply-avatar {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    object-fit: cover;
}
.ov-reply-input {
    flex: 1;
    min-height: 1.4rem;
    outline: none;
    border: none;
    border-bottom: 1px solid var(--border-card);
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-style: italic;
    color: var(--text-primary);
    padding-bottom: 0.25rem;
    transition: border-color 0.2s ease;
}
.ov-reply-input:empty::before {
    content: attr(data-placeholder);
    color: var(--text-faint);
    cursor: text;
}
.ov-reply-input:focus {
    border-bottom: 2px solid var(--accent-amber);
}

.ov-btn-row {
    display: flex;
    gap: 0.6rem;
    justify-content: flex-end;
    overflow: hidden;
}
.ov-btn-cancel {
    cursor: pointer;
    background-color: transparent;
    border: 1px solid var(--border-card);
    color: var(--text-primary);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 500;
    transition: background-color 0.15s ease;
}
.ov-btn-cancel:hover {
    background-color: var(--bg-hover);
}
.ov-btn-submit {
    cursor: pointer;
    border: none;
    padding: 0.35rem 1rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    transition: opacity 0.15s ease;
}
.ov-btn-submit:hover {
    opacity: 0.88;
}
.ov-btn-submit.ov-btn-disabled {
    cursor: default;
    user-select: none;
    opacity: 0.45;
}

/* ── Reply Card (rc-) ── */
.rc-thread {
    padding-left: calc(var(--depth, 0) * 1.25rem);
    width: 100%;
    box-sizing: border-box;
}

.rc-card {
    position: relative;
    display: flex;
    align-items: stretch;
    padding: 0.75rem 0;
    border-bottom: 1px solid var(--border-card);
}
.rc-card:last-child {
    border-bottom: none;
}

.rc-thread-line {
    position: absolute;
    left: -0.65rem;
    top: 0;
    bottom: 0;
    width: 2px;
    background-color: var(--border-card);
    border-radius: 1px;
    transition: background-color 0.2s ease;
}
.rc-card:hover > .rc-thread-line {
    background-color: var(--accent-amber);
}

.rc-content {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    flex: 1;
    min-width: 0;
}

.rc-user-row {
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.rc-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.rc-username {
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-heading);
}
.rc-dot {
    color: var(--text-separator);
    font-size: 0.75rem;
    line-height: 1;
}
.rc-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

.rc-body {
    font-family: var(--font-serif);
    font-size: 0.85rem;
    line-height: 1.65;
    color: var(--text-body);
}

.rc-action-row {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding-top: 0.15rem;
}
.rc-toggle-btn {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.2rem 0.4rem;
    border-radius: 6px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-muted);
    transition: color 0.15s ease, background-color 0.15s ease;
}
.rc-toggle-btn:hover {
    color: var(--accent-amber);
    background-color: var(--bg-pill);
}

.rc-reply-input-wrapper {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    overflow: hidden;
    padding-top: 0.25rem;
}

.rc-load-more {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    background: none;
    border: 1px solid var(--border-card);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    margin-top: 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--accent-amber);
    transition: background-color 0.15s ease;
}
.rc-load-more:hover {
    background-color: var(--bg-pill);
}
