                        ease: "easeOut"
                        }
                    }}
                    >
                        {links.map((link, index) =>(
                            <div onClick={() => handleClickLinks(link.path)} key={index} className='header-link'>
                                {link.label}
                                <div className={link.path === location.pathname ? "header-underline" : ''}></div>
