        <AnimatePresence>
        <div className="visited-profile-opinions-container">
            {opinions.map((opinion, index) => (
                <motion.div
                    className="so-card-wrapper"
                    key={opinion.id}
                    custom={index}
                    initial="hidden"
                    animate="visible"
                    variants={cardVariants}
