        width: 24px;
        height: 24px;
    }
    .rc-avatar {
        width: 18px;
        height: 18px;
    }
    .rc-username {
        font-size: 0.72rem;
        max-width: 100px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .rc-body {
        font-size: 0.8rem;
    }
    .rc-show-replies,
    .rc-reply-btn {
        font-size: 0.68rem;
    }
    .rc-load-more {
        font-size: 0.7rem;
        margin-left: calc(24px + 0.65rem);
    }

