        right: 1.25rem;
        bottom: 6.5rem;
        width: 54px;
        height: 54px;
    }
}
@media(max-width: 432px){
    .oe-card {
        width: 92%;
    }

    .write-opinion-fab {
        right: 1rem;
        bottom: 6rem;
        width: 50px;
        height: 50px;
    }
}

